文字相关禁止用户选中文本user-select: none;-ms-user-select: none; // 兼容ie-moz-user-select: none; // 兼容火狐


文字阴影// 发光效果text-shadow: 0 0 60px #fff // 四个参数分别为：阴影偏移 模糊半径 阴影颜色// 双重文字效果text-shadow: 5px 5px 0 #666// 3d文字效果text-shadow: 0 0 1px #999,             2px 2px 2px #888,             4px 4px 2px #777,             6px 6px 2px #666,             8px 8px 2px #555,             10px 10px 2px #333;

垂直文字writing-mode: vertical-rl; // 这个属性有五个值// horizontal-tb: 水平方向自上而下// vertical-rl:   垂直方向自右而做// sideways-rl:   垂直方向自上而下// sideways-lr:   垂直方向自下而上// vertical-lr:   垂直方向由上到下，水平方向从左到右

文字选中样式::selection &#123;  color: #fff;  background-color: red;&#125;-moz::selection &#123; // 兼容火狐  color: #fff;  background-color: red;&#125;

文字下划线text-decoration: underline red wavy; // 线条位置 线条颜色 线条形状


边框图border: 1px solid transparent; // 要使用border-iamge的前提是有一个完整的border属性border-image: url(../abc.png), 30 40, stretch;// 第一个参数表示图片路径，第二个参数为上下的边框大小和左右的边框大小，和边距的数字类似，第三个参数表示拉伸图片

瀑布流column-count: 4; // 瀑布流的列数 column-gap: 20px; // 每列之间的间距

网站去色html &#123;  filter: grayscale(50%); // 灰度滤镜&#125;
